async function importPharmacies() {
    console.log("🏥 Début import pharmacies...");
    // Vider les pharmacies existantes
    await prisma.pharmacy.deleteMany();
    console.log("🗑️  Anciennes pharmacies supprimées");
    // Créer/trouver les grossistes
    const grossisteNames = ["COPHARMED", "DPCI", "LABOREX", "TEDIS"];
    const grossisteMap = {};
    for (const name of grossisteNames) {
        let g = await prisma.grossiste.findFirst({ where: { name } });
        if (!g)
            g = await prisma.grossiste.create({ data: { name } });
        grossisteMap[name] = g.id;
        console.log(`  ✅ Grossiste: ${name}`);
    }
    console.log(`\n📊 Pharmacies à importer: ${PHARMACIES_DATA.length}`);
    // Import par batch de 100
    let imported = 0;
    let errors = 0;
    const BATCH = 100;
    for (let i = 0; i < PHARMACIES_DATA.length; i += BATCH) {
        const batch = PHARMACIES_DATA.slice(i, i + BATCH);
        try {
            await prisma.pharmacy.createMany({
                data: batch.map((p) => ({
                    nom: p.nom,
                    ville: p.zone,
                    region: p.zone,
                    grossisteId: grossisteMap[p.grossiste],
                    isActive: true,
                })),
                skipDuplicates: true,
            });
            imported += batch.length;
            if (i % 500 === 0)
                console.log(`  ... ${imported}/${PHARMACIES_DATA.length}`);
        }
        catch (err) {
            errors++;
            console.error(`  ❌ Erreur batch ${i}:`, err.message?.slice(0, 80));
        }
    }
    const total = await prisma.pharmacy.count();
    console.log(`\n🎉 Import terminé — Total en base: ${total}`);
    console.log(`   ❌ Erreurs batch: ${errors}`);
    await prisma.$disconnect();
}
importPharmacies().catch((e) => {
    console.error(e);
    prisma.$disconnect();
    process.exit(1);
});
